import os
import shlex
import subprocess
from urllib.parse import unquote


def image_convert(event, context):
    bucket = event.get("bucket", "")
    name = unquote(event.get("name", ""))
    metadata = event.get("metadata") or {}

    if not bucket or not name:
        return

    filename = os.path.basename(name)
    src_path = os.path.join("/tmp", filename)

    input_filename = metadata.get("filename", filename)
    output_filename = metadata.get("output", f"converted_{filename}")
    options = metadata.get("options", "")

    if os.path.exists(src_path):
        os.remove(src_path)

    os.system(f"gsutil cp gs://{bucket}/{shlex.quote(name)} {shlex.quote(src_path)}")

    cmd = f"convert {options} {input_filename} {output_filename}"
    subprocess.call(cmd, shell=True)

    if os.path.exists(output_filename):
        os.system(f"gsutil cp {shlex.quote(output_filename)} gs://{bucket}/{shlex.quote(output_filename)}")